SELECT COUNT(*) AS QUANTIDADE FROM LATTES_P_EVENTO PE JOIN LATTES_EVENTO E ON E.PK = PE.FK_EVENTO JOIN SERVIDOR S ON S.PK_SIAPE = PE.FK_SIAPE WHERE E.ANO = 2025 AND LOWER(PE.TIPO) LIKE LOWER('%apresenta%') AND LOWER(PE.TIPO) LIKE LOWER('%oral%') AND S.SIGLA_CAMPUS = 'ANA' AND (LOWER(COALESCE(S.AREA_INGRESSO, '')) LIKE '%letras%' OR LOWER(COALESCE(S.AREA_INGRESSO_OG, '')) LIKE '%letras%')